variables.errorRateQuery:
[concat('let timeframe = 5m;
', 'let minRequests = ', string(parameters('minRequestsForRate')), ';
', 'let thresholdPct = ', string(parameters('errorRateThresholdPct')), ';
', 'requests
', '| where timestamp > ago(timeframe)
', '| where cloud_RoleName =~ ', ''', roleName, ''', '
', '| summarize total = count(), failures = countif(success == false)
', '| extend errorRatePct = iff(total == 0, 0.0, todouble(failures) * 100.0 / todouble(total))
', '| where total >= minRequests and errorRatePct >= thresholdPct
')]

variables.latencyP95Query:
[concat('let timeframe = 5m;
', 'let minRequests = ', string(parameters('minRequestsForLatency')), ';
', 'let thresholdMs = ', string(parameters('p95LatencyMs')), ';
', 'requests
', '| where timestamp > ago(timeframe)
', '| where cloud_RoleName =~ ', ''', roleName, ''', '
', '| summarize total = count(), p95Ms = percentile(duration, 95)
', '| where total >= minRequests and p95Ms >= thresholdMs
')]

variables.crashSpikeQuery:
[concat('let recentWindow = 5m;
', 'let baselineWindow = 30m;
', 'let minCrashes = ', string(parameters('minCrashCount')), ';
', 'let spikeMultiplier = ', string(parameters('crashSpikeMultiplier')), ';
', 'let recent = toscalar(
', '  exceptions
', '  | where timestamp > ago(recentWindow)
', '  | where cloud_RoleName =~ ', ''', roleName, ''', '
', '  | summarize c = count()
', ');
', 'let baseline = toscalar(
', '  exceptions
', '  | where timestamp between (ago(recentWindow + baselineWindow) .. ago(recentWindow))
', '  | where cloud_RoleName =~ ', ''', roleName, ''', '
', '  | summarize c = count()
', ');
', 'let baselinePerWindow = iif(baseline == 0, 0.0, todouble(baseline) / 6.0);
', 'print recent = recent, baselinePerWindow = baselinePerWindow
', '| where recent >= minCrashes and (baselinePerWindow == 0.0 or todouble(recent) >= baselinePerWindow * spikeMultiplier)
')]
